phase1.code:
class Animal {
    void makeSound() {
        System.out.println("Some generic animal sound");
    }
}

class Dog extends Animal {
    @Override  // Annotation - tells compiler we're overriding
    void makeSound() {
        System.out.println("Woof! Woof!");
    }
}

class Cat extends Animal {
    @Override
    void makeSound() {
        System.out.println("Meow~ Meow~");
    }
}

class Cow extends Animal {
    @Override
    void makeSound() {
        System.out.println("Moo! Moo!");
    }
}

public class OverridingExample {
    public static void main(String[] args) {
        Animal animal = new Animal();
        Dog dog = new Dog();
        Cat cat = new Cat();
        Cow cow = new Cow();

        animal.makeSound();  // Parent method
        dog.makeSound();     // Overridden
        cat.makeSound();     // Overridden
        cow.makeSound();     // Overridden

        // Runtime polymorphism
        System.out.println("--- Runtime Polymorphism ---");
        Animal myDog = new Dog();
        Animal myCat = new Cat();

        myDog.makeSound();  // Calls Dog's version (runtime)
        myCat.makeSound();  // Calls Cat's version (runtime)
    }
}

